// ===============================================================
// TAB SWITCH
// ===============================================================
function toggleSidebar(forceHide){
  const layout=$('mainLayout');
  const btn=$('sbToggleBtn');
  const hidden = forceHide !== undefined
    ? (forceHide ? layout.classList.add('sb-hidden') || true : layout.classList.remove('sb-hidden') || false)
    : layout.classList.toggle('sb-hidden');
  const isHidden = layout.classList.contains('sb-hidden');
  localStorage.setItem('atw_sb_hidden', isHidden?'1':'0');
  if(btn){
    btn.title = isHidden ? 'Tampilkan sidebar [S]' : 'Sembunyikan sidebar [S]';
  }
  if(!isHidden&&activeTab==='wbs')setTimeout(renderWBS,250);
  if(!isHidden&&activeTab==='daily')setTimeout(renderDailyReport,250);
}

function restoreSidebarState(){
  const hidden=localStorage.getItem('atw_sb_hidden')==='1';
  if(hidden){
    $('mainLayout')?.classList.add('sb-hidden');
    const btn=$('sbToggleBtn');
    if(btn)btn.title='Tampilkan sidebar [S]';
  }
}

// Keyboard shortcut S untuk toggle sidebar
document.addEventListener('keydown',e=>{
  const inInput=['INPUT','TEXTAREA','SELECT'].includes(document.activeElement?.tagName);
  // S = toggle sidebar
  if(e.key==='s'&&!e.ctrlKey&&!e.metaKey&&!e.altKey&&!inInput){
    toggleSidebar();
  }
  // Esc = tutup dropdown notif atau modal
  if(e.key==='Escape'){
    const nd=$('notifDropdown');
    if(nd&&nd.classList.contains('open')){nd.classList.remove('open');return;}
    const om=document.querySelector('.modal-overlay:not([style*="display: none"]):not([style*="display:none"])');
    if(om)om.style.display='none';
  }
  // Digit 1-8 = switch tab (jangan saat di input)
  if(!inInput&&!e.ctrlKey&&!e.metaKey&&!e.altKey){
    const tabMap={'1':'overview','2':'projects','3':'manpower','4':'issues','5':'procurement','6':'wbs','7':'daily','8':'weekly'};
    const t=tabMap[e.key];
    if(t){
      const tabEl=document.querySelector(`.tab[onclick*="'${t}'"]`)||document.querySelector(`.tab[onclick*='"${t}"']`);
      if(tabEl)tabEl.click();
    }
  }
});

// ===============================================================
// NOTIFICATION BELL
// ===============================================================
function toggleNotif(e){
  e.stopPropagation();
  const dd=$('notifDropdown');
  if(!dd)return;
  const open=dd.classList.contains('open');
  if(!open){
    updateNotif();
    // Posisi dropdown tepat di bawah tombol bell, aligned kanan
    const btn=$('notifBtn');
    if(btn){
      const r=btn.getBoundingClientRect();
      dd.style.top=(r.bottom+6)+'px';
      dd.style.right=(window.innerWidth-r.right)+'px';
      dd.style.left='auto';
    }
  }
  dd.classList.toggle('open',!open);
}
document.addEventListener('click',e=>{
  const wrap=$('notifWrap');
  if(wrap&&!wrap.contains(e.target)){
    const dd=$('notifDropdown');
    if(dd)dd.classList.remove('open');
  }
});
function updateNotif(){
  const items=[];
  const today=new Date();today.setHours(0,0,0,0);
  // 1. Overdue procurement
  const overdue=PROC.filter(i=>i.status==='Overdue'||(() => {
    if(!i.due||i.status==='On Site'||i.status==='Done')return false;
    const d=parseLocalDate(i.due);d.setHours(0,0,0,0);
    return d<today;
  })());
  if(overdue.length)items.push({ico:'📦',color:'var(--rd)',title:`${overdue.length} Item Procurement Overdue`,sub:overdue.slice(0,2).map(i=>i.item).join(', ')+(overdue.length>2?` +${overdue.length-2} lagi`:''),tab:'procurement'});
  // 2. Due hari ini / ≤3 hari
  const dueSoon=PROC.filter(i=>{
    if(!i.due||i.status==='On Site'||i.status==='Done'||i.status==='Overdue')return false;
    const d=parseLocalDate(i.due);d.setHours(0,0,0,0);
    const diff=Math.ceil((d-today)/86400000);
    return diff>=0&&diff<=3;
  });
  if(dueSoon.length)items.push({ico:'<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;display:inline-block"><circle cx="12" cy="12" r="9"/><polyline points="12 7 12 12 15 15"/><line x1="12" y1="19" x2="12" y2="19.01"/></svg>',color:'var(--yw)',title:`${dueSoon.length} Procurement Jatuh Tempo ≤3 Hari`,sub:dueSoon.slice(0,2).map(i=>i.item).join(', ')+(dueSoon.length>2?` +${dueSoon.length-2} lagi`:''),tab:'procurement'});
  // 3. Critical projects
  const crits=P.filter(p=>p.status==='Critical');
  if(crits.length)items.push({ico:'●',color:'var(--rd)',title:`${crits.length} Project Status Critical`,sub:crits.map(p=>p.kode).join(', '),tab:'projects'});
  // 4. Open high-priority issues
  const highIss=ISS.filter(i=>i.status!=='Closed'&&(i.prioritas==='High'||i.priority==='High'));
  if(highIss.length)items.push({ico:'⚠️',color:'var(--rd)',title:`${highIss.length} Issue Priority High Belum Closed`,sub:highIss.slice(0,2).map(i=>i.uraian||i.subject||i.title||'Issue').join(', ')+(highIss.length>2?` +${highIss.length-2} lagi`:''),tab:'issues'});
  // 5. Delayed projects
  const del=P.filter(p=>p.status==='Delayed');
  if(del.length)items.push({ico:'<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;display:inline-block"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg>',color:'var(--yw)',title:`${del.length} Project Delayed`,sub:del.map(p=>p.kode).join(', '),tab:'projects'});
  // 6. RAB over/near budget
  if(typeof RAB!=='undefined'&&RAB.length){
    P.forEach(p=>{
      const kats=RAB.filter(r=>r.type==='kat'&&String(r.projId)===String(p.id));
      if(!kats.length)return;
      const items2=RAB.filter(r=>r.type==='item'&&String(r.projId)===String(p.id));
      if(!items2.length)return;
      const actByKat=typeof getRabActualByKat==='function'?getRabActualByKat(p.id):{};
      const overKats=kats.filter(k=>{const rk=items2.filter(i=>i.katId===k.id).reduce((s,i)=>s+(+i.total||0),0);return rk>0&&(actByKat[k.id]||0)>=rk;});
      const nearKats=kats.filter(k=>{const rk=items2.filter(i=>i.katId===k.id).reduce((s,i)=>s+(+i.total||0),0);const act=actByKat[k.id]||0;return rk>0&&act/rk>=0.9&&act<rk;});
      if(overKats.length)items.push({ico:'⚑',color:'var(--rd)',title:`${p.kode}: ${overKats.length} Kategori RAB OVER Budget`,sub:overKats.map(k=>k.name).join(', '),tab:'cost'});
      else if(nearKats.length)items.push({ico:'⚠️',color:'var(--yw)',title:`${p.kode}: ${nearKats.length} Kategori RAB Mendekati Limit`,sub:nearKats.map(k=>k.name).join(', '),tab:'cost'});
    });
  }
  // Update badge
  const badge=$('notifBadge');
  const total=items.length;
  if(badge){badge.textContent=total>9?'9+':total;badge.classList.toggle('hidden',total===0);}
  // Update dropdown
  const list=$('notifList');
  const timeEl=$('notifTime');
  if(timeEl)timeEl.textContent=new Date().toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'});
  if(!list)return;
  if(!items.length){list.innerHTML='<div class="notif-empty">✓ Tidak ada alert aktif</div>';return;}
  list.innerHTML=items.map(it=>`<div class="notif-item" onclick="(function(){const te=document.querySelector('.tab[onclick*=\\'${it.tab}\\']');if(te)sw('${it.tab}',te);$('notifDropdown').classList.remove('open');})()">
    <div class="ni-ico">${it.ico}</div>
    <div class="ni-body">
      <div class="ni-title" style="color:${it.color}">${it.title}</div>
      <div class="ni-sub">${it.sub}</div>
    </div>
  </div>`).join('');
}
