function sw(t,el){
  activeTab=t;
  document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));
  el.classList.add('active');
  document.querySelectorAll('.tp').forEach(x=>x.classList.remove('active'));
  $('tp-'+t).classList.add('active');
  // Sync project selector sebelum render
  if(selId) _syncAllProjSelectors(selId);
  if(t==='overview')renderOV();
  if(t==='projects')renderProjTab();
  if(t==='manpower'){renderMP();setTimeout(()=>renderMpLog&&renderMpLog(),100);}
  if(t==='issues')renderIssues();
  if(t==='procurement')renderProc();
  if(t==='wbs'){
    renderWBS(); // renderWBS sudah memanggil renderWbsSCurve di akhir
  }
  if(t==='daily')renderDailyReport();
  if(t==='cost'){
    const cfp=$('costFiltProj');if(cfp)cfp._costFiltManual=false;
    const rfp=$('rabFiltProj');if(rfp&&selId)rfp.value=selId;
    renderCost();renderRab();
  }
  if(t==='scurve')renderSCurve();
}

