function render(){
  renderSB();
  updateBadge();
  updateGsBadge();
  if(typeof updateNotif==='function')updateNotif();
  if($('btnUpd'))$('btnUpd').disabled=!selId;
  if(activeTab==='overview')renderOV();
  if(activeTab==='projects')renderProjTab();
  if(activeTab==='manpower')renderMP();
  if(activeTab==='issues')renderIssues();
  if(activeTab==='procurement')renderProc();
  if(activeTab==='cost'){renderCost();renderRab();}
}
function updateBadge(){
  const n=ISS.filter(i=>i.status!=='Closed').length;
  $('ibadge').textContent=n>0?n:'';
}
function toggleSbarDD(id){
  // Close all open dropdowns
  document.querySelectorAll('.sbar-dd-menu.open').forEach(m=>{
    m.classList.remove('open');
    m.style.display='none';
    if(m._origParent)m._origParent.appendChild(m);
  });
  const menu=document.getElementById(id+'Menu');
  if(!menu||menu._justClosed)return;
  const btn=document.querySelector('#'+id+' .btn');
  if(!btn)return;
  const r=btn.getBoundingClientRect();
  if(!menu._origParent)menu._origParent=menu.parentElement;
  document.body.appendChild(menu);
  menu.style.cssText='display:block;position:fixed;top:'+(r.bottom+4)+'px;right:'+(window.innerWidth-r.right)+'px;background:var(--sf2);border:1px solid var(--bd);border-radius:7px;min-width:165px;z-index:2147483647;padding:4px;box-shadow:0 8px 24px rgba(0,0,0,.6)';
  menu.classList.add('open');
}
// Close dropdowns when clicking outside
document.addEventListener('click',e=>{
  if(!e.target.closest('.sbar-dd')&&!e.target.closest('.sbar-dd-menu')){
    document.querySelectorAll('.sbar-dd-menu.open').forEach(m=>{
      m.classList.remove('open');
      m.style.display='none';
      if(m._origParent)m._origParent.appendChild(m);
    });
  }
});

