function toggleSidebar(){
  const layout=document.getElementById('mainLayout');
  const btn=document.getElementById('sbToggleBtn');
  const arrow=btn?.querySelector('.sb-arrow');
  const hidden=layout.classList.toggle('sidebar-hidden');
  if(arrow)arrow.textContent=hidden?'\u25B6':'\u25C0';
  if(btn)btn.title=hidden?'Tampilkan sidebar':'Sembunyikan sidebar';
  if(hidden){
    if(btn)btn.style.cssText='position:fixed;top:50vh;left:0;transform:translateY(-50%);z-index:100';
  }else{
    if(btn)btn.style.cssText='';
  }
  localStorage.setItem('atw_sidebar',hidden?'0':'1');
}

// Restore sidebar state on load
(function(){
  if(localStorage.getItem('atw_sidebar')==='0'){
    document.addEventListener('DOMContentLoaded',()=>{
      const layout=document.getElementById('mainLayout');
      const btn=document.getElementById('sbToggleBtn');
      const arrow=btn?.querySelector('.sb-arrow');
      if(layout)layout.classList.add('sidebar-hidden');
      if(arrow)arrow.textContent='\u25B6';
      if(btn)btn.style.cssText='position:fixed;top:50vh;left:0;transform:translateY(-50%);z-index:100';
    });
  }
})();

function renderSB(){
  $('pcount').textContent=P.length;
  const sc={'On Track':'p-on','Delayed':'p-del','Critical':'p-crit','Planning':'p-plan','Done':'p-done'};
  const bc={'On Track':'var(--gn)','Delayed':'var(--yw)','Critical':'var(--rd)','Planning':'var(--bl)','Done':'var(--pu)'};
  $('projList').innerHTML=P.map(p=>`
    <div class="pi ${p.id===selId?'active':''}" onclick="selProj('${p.id}')">
      <div style="display:flex;align-items:center;gap:7px;margin-bottom:4px">
        ${p.logo?`<div style="width:32px;height:32px;background:var(--sf2);border:1px solid var(--bd);border-radius:6px;display:flex;align-items:center;justify-content:center;overflow:hidden;flex-shrink:0;padding:3px">
          <img src="${p.logo}" style="max-width:26px;max-height:26px;object-fit:contain" onerror="this.parentElement.style.display='none'">
        </div>`:''}
        <div style="flex:1;min-width:0">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:3px">
            <div class="pi-name">${p.nama}</div><span class="pill ${sc[p.status]||'p-plan'}">${p.status}</span>
          </div>
          <div class="pi-loc"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="vertical-align:-2px;display:inline-block"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>${p.lokasi||'\u2014'}</div>
        </div>
      </div>
      <div class="pi-bar"><div class="pi-fill" style="width:${p.actual}%;background:${bc[p.status]||'var(--bl)'}"></div></div>
      <div class="pi-meta">
        <span style="color:var(--mt)">Actual <span style="font-family:var(--fm);color:${bc[p.status]||'var(--bl)'}">${p.actual}%</span></span>
        <span style="color:var(--mt)">Plan <span style="font-family:var(--fm)">${p.plan}%</span></span>
      </div>
    </div>`).join('')||'<div style="padding:16px;text-align:center;color:var(--mt);font-size:11px">Belum ada project</div>';
}
function onWbsProjChange(id){
  selId=String(id);
  _syncAllProjSelectors(id);
  renderSB();
  // Destroy chart & hide section sebelum render project baru
  if(window._wbsChart){window._wbsChart.destroy();window._wbsChart=null;}
  const sec=$('wbsScSection');if(sec)sec.style.display='none';
  renderWBS();
}

function onDrProjChange(id){
  selId=String(id);
  _syncAllProjSelectors(id);
  renderSB();
  renderDailyReport();
}

function selProj(id){
  selId=String(id);
  if($('btnUpd'))$('btnUpd').disabled=false;
  // Reset manual filter flags agar selector ikut project yang diklik di sidebar
  const pfe=document.getElementById('procFiltProj');if(pfe)pfe._procFiltManual=false;
  const mfe=document.getElementById('mpLogFiltProj');if(mfe)mfe._mpFiltManual=false;
  // Sync semua project selector di semua tab
  _syncAllProjSelectors(selId);
  renderSB();
  renderDetail(selId);
  // Jika sedang di tab WBS atau Daily, langsung render
  if(activeTab==='wbs')renderWBS();
  else if(activeTab==='daily')renderDailyReport();
}

function _syncAllProjSelectors(id){
  const sid=String(id);
  // Helper rebuild all options
  const rebuildOpts=(el,withAll)=>{
    el.innerHTML=(withAll?'<option value="">Semua Project</option>':'')+
      P.map(p=>`<option value="${p.id}">${p.kode} \u2014 ${p.nama}</option>`).join('');
  };

  // Sync WBS & Daily Report dropdowns (no "Semua Project")
  ['wbsProjSel','drProjSel'].forEach(elId=>{
    const el=document.getElementById(elId);
    if(!el)return;
    rebuildOpts(el,false);
    el.value=sid;
  });

  // Sync procurement filter
  const procEl=document.getElementById('procFiltProj');
  if(procEl){
    rebuildOpts(procEl,true);
    if(!procEl._procFiltManual) procEl.value=sid;
    if(activeTab==='procurement')renderProc();
  }

  // Sync manpower log filter
  const mpEl=document.getElementById('mpLogFiltProj');
  if(mpEl){
    rebuildOpts(mpEl,true);
    if(!mpEl._mpFiltManual) mpEl.value=sid;
    if(activeTab==='manpower')renderMpLog?.();
  }

  // Sync manpower ACTIVITY rekap filter
  const mpActEl=document.getElementById('mpActFiltProj');
  if(mpActEl){
    rebuildOpts(mpActEl,true);
    if(!mpActEl._mpActFiltManual) mpActEl.value=sid;
    if(activeTab==='manpower')renderMpActivity?.();
  }

  // Sync manpower INPUT modal dropdown
  const mpProjEl=document.getElementById('mpProj');
  if(mpProjEl){
    const curVal=mpProjEl.value;
    rebuildOpts(mpProjEl,false);
    // Pertahankan pilihan yang sudah ada jika masih valid, atau set ke selId
    mpProjEl.value=curVal&&P.find(p=>String(p.id)===curVal)?curVal:sid;
  }

  // Sync cost/finance filter
  const costEl=document.getElementById('costFiltProj');
  if(costEl){
    rebuildOpts(costEl,true);
    costEl._costFiltManual=false;costEl.value=sid;
    if(activeTab==='cost')renderCost();
  }

  // Sync RAB filter
  const rabEl=document.getElementById('rabFiltProj');
  if(rabEl){
    rebuildOpts(rabEl,false);
    rabEl.innerHTML='<option value="">\u2014 Pilih Project \u2014</option>'+
      P.map(p=>`<option value="${p.id}">${p.kode} \u2014 ${p.nama}</option>`).join('');
    rabEl.value=sid;
    if(activeTab==='cost')renderRab();
  }
}


