async function _gsSyncWithCosts(costsArr){
  if(!gsOk||!gsUrl)return;
  try{
    const hist=[];P.forEach(p=>(p.history||[]).forEach(h=>hist.push({...h,projId:p.id,kode:p.kode})));
    const lTs=JSON.parse(localStorage.getItem('atw_data')||'{}').ts||Date.now();
    const user=localStorage.getItem('atw_user')||'user';
    const body=JSON.stringify({action:'sync',lastSaved:lTs,user,projects:P,history:hist,
      issues:ISS,procurement:PROC,manpowerLogs:MPLOGS,accidentLogs:ACCLOGS,
      scurve:SCURVE,wbs:WBS,costs:costsArr,rab:RAB});
    const r=await fetch(gsUrl,{method:'POST',body,headers:{'Content-Type':'text/plain;charset=utf-8'}});
    if(r.ok){
      const d=JSON.parse(await r.text());
      if(d.status==='ok'){
        clearPendingDeletesCost();
        console.log('GS delete sync OK');
      }
    }
  }catch(e){console.warn('GS delete sync failed:',e.message);}
}

function gsSync(){
  if(!gsOk||!gsUrl)return;
  // Debounce \u2014 jangan sync terlalu sering
  if(gsSync._pending)clearTimeout(gsSync._pending);
  gsSync._pending=setTimeout(async()=>{
    gsSync._pending=null;
    try{
      const hist=[];P.forEach(p=>(p.history||[]).forEach(h=>hist.push({...h,projId:p.id,kode:p.kode})));
      const user=localStorage.getItem('atw_user')||'user';
      // Gunakan ts dari localStorage (waktu data terakhir diubah lokal), bukan Date.now()
      // Ini penting agar conflict detection di server bisa bekerja dengan benar
      const lTs=JSON.parse(localStorage.getItem('atw_data')||'{}').ts||Date.now();
      // Sertakan soft-deleted cost records agar GSheet bisa hapus via mergeById(allowDelete)
      const pendingCostDels=[...getPendingDeletesCost()];
      const costsWithDeleted=[...COSTS,...pendingCostDels.filter(id=>!COSTS.find(c=>String(c.id)===id)).map(id=>({id,_deleted:true}))];
      const body=JSON.stringify({action:'sync',lastSaved:lTs,user,projects:P,history:hist,issues:ISS,procurement:PROC,manpowerLogs:MPLOGS,accidentLogs:ACCLOGS,scurve:SCURVE,wbs:WBS,costs:costsWithDeleted,rab:RAB});
      const r=await fetch(gsUrl,{method:'POST',body,headers:{'Content-Type':'text/plain;charset=utf-8'}});
      if(r.ok){
        const txt=await r.text();
        try{
          const d=JSON.parse(txt);
          if(d.status==='ok'){
            console.log('GS sync OK',d.ts);
            clearPendingDeletesCost(); // bersihkan setelah berhasil sync
          }else if(d.status==='conflict'){
            // Server lebih baru \u2014 load ulang dari GSheet lalu sync lagi
            console.warn('GS conflict detected, reloading...');
            await loadFromGS();
          }else if(d.status==='error'&&d.msg==='Server busy, coba lagi'){
            // Retry after 3s
            setTimeout(()=>gsSync(),3000);
          }
        }catch(e){}
      }
    }catch(e){
      try{
        const hist=[];P.forEach(p=>(p.history||[]).forEach(h=>hist.push({...h,projId:p.id,kode:p.kode})));
        fetch(gsUrl,{method:'POST',body:JSON.stringify({action:'sync',lastSaved:Date.now(),projects:P,history:hist,issues:ISS,procurement:PROC,manpowerLogs:MPLOGS,accidentLogs:ACCLOGS,scurve:SCURVE,wbs:WBS,costs:COSTS}),headers:{'Content-Type':'text/plain'},mode:'no-cors'});
      }catch(e2){}
    }
  },800); // debounce 800ms
}
