// ── PERFORMANCE: passive listeners & scroll optimization ──
(function(){
  // Make all scroll/touch listeners passive by default
  const orig=EventTarget.prototype.addEventListener;
  EventTarget.prototype.addEventListener=function(type,fn,opts){
    if(['scroll','touchstart','touchmove','wheel','mousewheel'].includes(type)){
      if(typeof opts==='boolean'||opts==null)opts={passive:true,capture:opts||false};
      else if(typeof opts==='object'&&opts.passive==null)opts={...opts,passive:true};
    }
    return orig.call(this,type,fn,opts);
  };
  // requestAnimationFrame wrapper for scroll handlers
  window._raf=null;
  window._scheduleRender=cb=>{
    if(window._raf)return;
    window._raf=requestAnimationFrame(()=>{window._raf=null;cb();});
  };
})();

// ===============================================================
// ===============================================================
// STARTUP \u2014 GSheet adalah sumber kebenaran (source of truth)
// localStorage hanya sebagai cache offline, TIDAK pernah mendahului GSheet
// ===============================================================
async function autoLoadOnStart(){
  // LANGKAH 1: load dari localStorage sebagai tampilan sementara (offline fallback)
  const hasLocal = loadLocal();
  if(hasLocal){
    loadLogosCache();
    selId=P[0]?.id||null;
    render();
    $('smsg').textContent='Memuat cache lokal \u2014 menghubungi GSheet...';
    $('sdot').style.background='var(--yw)';
  }else{
    render();
    $('smsg').textContent='Belum ada data \u2014 menghubungi GSheet...';
    $('sdot').style.background='var(--mt)';
  }

  // LANGKAH 2: GSheet selalu menjadi sumber kebenaran jika tersambung
  if(gsOk && gsUrl){
    try{
      const res=await fetch(gsUrl+'?t='+Date.now(),{cache:'no-cache'});
      if(!res.ok)throw new Error('HTTP '+res.status);
      const txt=await res.text();
      if(!txt||!txt.trim().startsWith('{'))throw new Error('Response bukan JSON: '+txt.slice(0,50));
      const d=JSON.parse(txt);
      if(d.status==='error')throw new Error(d.msg||'GSheet error');
      if(d.projects&&d.projects.length>0){
        // GSheet selalu menang \u2014 tidak perlu cek timestamp
        // localStorage hanya dipakai saat offline
        P=sanitizeProjects(d.projects);
        try{const lc=JSON.parse(localStorage.getItem('atw_logos')||'{}');P.forEach(p=>{if(!p.logo&&(lc[p.id]||lc[String(p.id)]))p.logo=lc[p.id]||lc[String(p.id)];});}catch(ex){}
        ISS=sanitizeIssues(d.issues);
        PROC=sanitizeProc(d.procurement);
        MPLOGS=sanitizeMpLogs(d.manpowerLogs);
        ACCLOGS=sanitizeAccLogs(d.accidentLogs);COSTS=sanitizeCosts(d.costs||[]);
        RAB=sanitizeRab(d.rab||[]);
        if(d.history){d.history.forEach(h=>{const p=P.find(x=>x.id==h.projId);if(p){if(!p.history)p.history=[];p.history.push(h);}});}
        selId=P[0]?.id||null;
        saveLocal(d.lastSaved||Date.now(),true); // cache data GSheet \u2014 bukan data lokal
        render();
        $('smsg').textContent='Tersinkronisasi dari Google Sheet ✓';
        $('sdot').style.background='var(--gn)';
        $('sdot').classList.remove('unsaved');
        $('flabel').textContent='Google Sheet · '+new Date().toLocaleTimeString('id-ID');
        // Simpan ts dari GSheet agar _rtPoll tidak re-render tanpa perlu
        try{const lts=JSON.parse(localStorage.getItem('atw_data')||'{}');lts.ts=d.lastSaved||Date.now();localStorage.setItem('atw_data',JSON.stringify(lts));}catch(e){}
        _rtLastTs=+d.lastSaved||0;
      }else{
        // GSheet kosong atau belum ada data \u2014 pakai lokal jika ada
        if(hasLocal){
          const localMeta=JSON.parse(localStorage.getItem('atw_data')||'{}');
          if(localMeta.fromGS){
            // Data lokal berasal dari GSheet sebelumnya \u2014 mungkin GSheet baru di-reset
            $('smsg').textContent='GSheet kosong · data cache lokal dimuat';
            $('sdot').style.background='var(--yw)';
          }else{
            // Data lokal benar-benar dibuat offline \u2014 push ke GSheet
            $('smsg').textContent='GSheet kosong \u2014 push data lokal ke GSheet...';
            $('sdot').style.background='var(--yw)';
            setTimeout(()=>gsSync(),1000);
          }
        }else{
          $('smsg').textContent='GSheet kosong \u2014 tambah project untuk memulai';
          $('sdot').style.background='var(--mt)';
        }
      }
      // Apply dash_logo dari GSheet
      if(d.dash_logo&&d.dash_logo.startsWith('data:')){
        try{localStorage.setItem('atw_dash_logo',d.dash_logo);const img=$('dashLogoImg');if(img)img.src=d.dash_logo;const btn=$('btnResetLogo');if(btn)btn.style.display='flex';}catch(e){}
      }
    }catch(e){
      // Offline / GSheet error \u2014 tetap pakai lokal sebagai fallback
      if(hasLocal){
        $('smsg').textContent='⚠ GSheet tidak terjangkau \u2014 menampilkan data cache lokal';
        $('sdot').style.background='var(--yw)';
        $('flabel').textContent='Cache Offline';
      }else{
        $('smsg').textContent='✗ Tidak dapat terhubung ke GSheet \u2014 tidak ada data lokal';
        $('sdot').style.background='var(--rd)';
      }
    }
  }else{
    // Tidak ada GSheet \u2014 pakai lokal saja
    if(hasLocal){
      loadLogosCache();
      $('smsg').textContent='Mode offline \u2014 GSheet belum dikonfigurasi';
      $('flabel').textContent='Lokal';
    }
  }
}

// ── URL PARAMS AUTO-CONNECT ──────────────────────────────────
function initFromUrlParams(){
  try{
    const params=new URLSearchParams(window.location.search);
    const gsParam=params.get('gs');  // URL Apps Script
    const shParam=params.get('sh');  // Sheet URL (opsional)
    if(gsParam&&!gsOk){
      // Auto-connect dari URL parameter
      gsUrl=decodeURIComponent(gsParam);
      gsSheet=shParam?decodeURIComponent(shParam):'';
      gsOk=true;
      localStorage.setItem('atw_gs',JSON.stringify({url:gsUrl,sheet:gsSheet}));
      updateGsBadge();
      // Bersihkan URL tanpa reload agar URL tidak tampil di address bar
      const cleanUrl=window.location.pathname;
      window.history.replaceState({},'',cleanUrl);
      toast('✓ Google Sheet tersambung otomatis via link!');
    }
  }catch(e){console.log('URL param init:',e);}
}

function copyShareUrl(){
  if(!gsOk||!gsUrl){toast('Setup Google Sheet dulu sebelum share link','warn');return;}
  const base=window.location.origin+window.location.pathname;
  const shareUrl=base+'?gs='+encodeURIComponent(gsUrl)+(gsSheet?'&sh='+encodeURIComponent(gsSheet):'');
  navigator.clipboard?.writeText(shareUrl).then(()=>{
    toast('✓ Link berhasil disalin! Bagikan ke tim Anda.');
  }).catch(()=>{
    // Fallback
    const ta=document.createElement('textarea');
    ta.value=shareUrl;document.body.appendChild(ta);ta.select();
    document.execCommand('copy');document.body.removeChild(ta);
    toast('✓ Link disalin ke clipboard!');
  });
}
