// AUTH \u2014 Password selalu dari GSheet, tidak disimpan di localStorage
const DEFAULT_PW={admin:'admin123',editor:'edit123'};
let gsPw={admin:null,editor:null}; // null = belum load dari GSheet
let gsPwLoaded=false;

function getRolePw(role){
  if(role==='viewer')return null;
  // Hanya gunakan GSheet password, fallback ke default jika belum load
  if(role==='admin')return gsPw.admin||DEFAULT_PW.admin;
  if(role==='editor')return gsPw.editor||DEFAULT_PW.editor;
  return null;
}

// Load password LANGSUNG dari GSheet \u2014 wajib sebelum login
// === AUTH FUNCTIONS MOVED TO js/auth.js ===
// doLogin, _loginSuccess, applyRole, doLogout, checkSession, initAuth, etc.


// AUTO-POLLING
// ===============================================================
// REAL-TIME SYNC ENGINE \u2014 Poll GSheet setiap 15 detik
// ===============================================================
let _rtLastTs=0;
let _rtOnline=true;
let _rtFailCount=0;
let _rtConnected=false;

// Online/offline indicator
window.addEventListener('online',  ()=>{ _rtOnline=true; _rtSetStatus('online'); setTimeout(_rtPoll,500); });
window.addEventListener('offline', ()=>{ _rtOnline=false; _rtSetStatus('offline'); });

function _rtSetStatus(s){
  const dot=$('sdot');const msg=$('smsg');
  if(s==='online')  { if(dot)dot.style.background='var(--gn)'; }
  if(s==='offline') { if(dot)dot.style.background='var(--rd)'; if(msg)msg.textContent='Offline \u2014 data terakhir ditampilkan'; }
  if(s==='syncing') { if(dot)dot.style.background='var(--yw)'; if(msg)msg.textContent='Sinkronisasi...'; }
  if(s==='synced')  { if(dot){dot.style.background='var(--gn)';dot.classList.remove('unsaved');} }
  if(s==='error')   { if(dot)dot.style.background='var(--yw)'; }
}

// Tombol retry manual yang muncul saat GSheet gagal
function _rtShowRetryBtn(){
  if($('rtRetryBtn'))return;
  const sbar=$('sbar');if(!sbar)return;
  const btn=document.createElement('button');
  btn.id='rtRetryBtn';btn.className='btn btn-sm';
  btn.style.cssText='border-color:var(--yw);color:var(--yw);animation:pulse 2s infinite';
  btn.textContent='\u21bb Coba Lagi';
  btn.onclick=()=>{
    btn.remove();_rtFailCount=0;
    if($('smsg'))$('smsg').textContent='Mencoba koneksi ulang...';
    if($('sdot'))$('sdot').style.background='var(--yw)';
    _rtPoll();
  };
  const btns=sbar.querySelector('.sbar-btns');
  if(btns)btns.insertBefore(btn,btns.firstChild);
}
function _rtHideRetryBtn(){ const b=$('rtRetryBtn');if(b)b.remove(); }

async function _rtPoll(){
  if(!gsOk||!gsUrl||!_rtOnline)return;
  const silentMode=isDirty;
  // Timeout manual — kompatibel semua browser & webview
  const controller=new AbortController();
  const timer=setTimeout(()=>controller.abort(),10000);
  try{
    const r=await fetch(gsUrl+'?t='+Date.now(),{cache:'no-store',signal:controller.signal});
    clearTimeout(timer);
    if(!r.ok)throw new Error('HTTP '+r.status);
    const txt=await r.text();
    if(!txt||!txt.trim().startsWith('{'))throw new Error('Response tidak valid');
    const d=JSON.parse(txt);
    if(d.status==='error')throw new Error(d.msg||'GSheet error');

    // Koneksi berhasil — reset semua fail state
    _rtFailCount=0;
    _rtConnected=true;
    _rtHideRetryBtn();

    if(!d.projects?.length){
      const now=new Date().toLocaleTimeString('id-ID');
      if($('smsg')&&!isDirty)$('smsg').textContent='GSheet \u2713 \u00b7 '+now;
      _rtSetStatus('synced');
      return;
    }

    const gTs=+d.lastSaved||0;

    // Data tidak berubah — update status saja tanpa re-render
    if(gTs>0&&gTs<=_rtLastTs){
      const now=new Date().toLocaleTimeString('id-ID');
      if($('smsg')&&!isDirty)$('smsg').textContent='GSheet \u2713 \u00b7 '+now;
      _rtSetStatus('synced');
      return;
    }
    _rtLastTs=gTs;

    // ================================================================
    // PROTEKSI DATA: Jangan update data lokal jika user sedang edit
    // (isDirty=true = ada perubahan lokal belum tersimpan)
    // Berlaku untuk SEMUA modul: WBS, Cost, Manpower, Procurement, dll
    // ================================================================
    if(!isDirty){
      // Smart merge \u2014 semua collection
      const prevProjCount=P.length;
      const prevProcCount=PROC.length;
  
      P=sanitizeProjects(d.projects);
      try{
        const lc=JSON.parse(localStorage.getItem('atw_logos')||'{}');
        P.forEach(p=>{if(!p.logo&&(lc[p.id]||lc[String(p.id)]))p.logo=lc[p.id]||lc[String(p.id)];});
      }catch(ex){}
  
      ISS=sanitizeIssues(d.issues);
  
      // Merge PROC by id
      const remP=sanitizeProc(d.procurement);
      const pm=new Map();
      PROC.forEach(p=>pm.set(String(p.id),p));
      remP.forEach(p=>pm.set(String(p.id),p));
      PROC=[...pm.values()];
  
      MPLOGS=sanitizeMpLogs(d.manpowerLogs);
      ACCLOGS=sanitizeAccLogs(d.accidentLogs);COSTS=sanitizeCosts(d.costs||[]);
      RAB=sanitizeRab(d.rab||[]);
  
      if(d.history){
        d.history.forEach(h=>{
          const p=P.find(x=>x.id==h.projId);
          if(p){if(!p.history)p.history=[];
            if(!p.history.find(x=>x.date===h.date&&x.actual===h.actual))p.history.push(h);}
        });
      }
  
      // Merge WBS by id — skip item yg baru saja dihapus lokal
      if(Array.isArray(d.wbs)&&d.wbs.length){
        const deleted=window._wbsRecentDeleted||new Set();
        const wm=new Map();
        WBS.forEach(w=>wm.set(String(w.id),w));
        // Remote data tidak boleh restore item yg baru saja dihapus lokal
        d.wbs.filter(w=>!deleted.has(String(w.id))).forEach(w=>wm.set(String(w.id),w));
        WBS=[...wm.values()].filter(w=>!deleted.has(String(w.id)));
        syncAllWbsToProjects();
      }
  
      if(Array.isArray(d.scurve)){
        SCURVE=d.scurve.map(s=>({
          projId:s.projId,week:+s.week||0,
          wPlan:+s.wPlan||0,wAct:+s.wAct||0,
          cPlan:s.cPlan!=null?+s.cPlan:null,
          cAct:s.cAct!=null?+s.cAct:null,
          dateStart:String(s.dateStart||''),fromWbs:s.fromWbs===true||s.fromWbs==='true'||s.fromWbs===1
        }));
      }
  
      selId=selId||(P[0]?.id||null);
      saveLocal(gTs||Date.now(),true); // data dari GSheet poll
    } // end if(!isDirty)

    // Apply dash_logo dari GSheet jika ada dan berbeda dari yang di localStorage
    if(d.dash_logo&&d.dash_logo.startsWith('data:')){
      try{
        const cur=localStorage.getItem('atw_dash_logo')||'';
        if(cur!==d.dash_logo){
          localStorage.setItem('atw_dash_logo',d.dash_logo);
          const img=$('dashLogoImg');if(img)img.src=d.dash_logo;
          const btn=$('btnResetLogo');if(btn)btn.style.display='flex';
        }
      }catch(e){}
    }

    // Jika user sedang edit (silentMode/isDirty), simpan ke memory tapi jangan re-render
    // agar form yang sedang diisi tidak terganggu
    if(!silentMode){
      _rtSmartRender();
    }

    const now=new Date().toLocaleTimeString('id-ID');
    if($('smsg')&&!isDirty)$('smsg').textContent='GSheet ✓ · '+now;
    _rtSetStatus('synced');

  }catch(e){
    clearTimeout(timer);
    _rtFailCount++;
    const isTimeout=(e.name==='AbortError');
    if(_rtFailCount===1){
      // Gagal pertama — diam saja, coba lagi di poll berikutnya
      if($('sdot'))$('sdot').style.background='var(--yw)';
    }else if(_rtFailCount>=2){
      // Gagal 2x berturut-turut — tampilkan info + tombol retry
      const errInfo=isTimeout?'timeout':'tidak terjangkau';
      if($('smsg'))$('smsg').textContent='GSheet '+errInfo+' \u2014 data lokal ditampilkan';
      _rtSetStatus('error');
      _rtShowRetryBtn();
    }
  }
}

function _rtSmartRender(){
  // Hanya render tab yang sedang aktif \u2014 lebih efisien
  renderSB();
  updateBadge();
  if(typeof updateNotif==='function')updateNotif();
  if(activeTab==='overview')renderOV();
  else if(activeTab==='projects'&&selId)renderDetail(selId);
  else if(activeTab==='manpower')renderMP();
  else if(activeTab==='issues')renderIssues?.();
  else if(activeTab==='procurement')renderProc();
  else if(activeTab==='cost'){renderCost();renderRab();}
  else if(activeTab==='wbs')renderWBS();
  else if(activeTab==='daily')renderDailyReport();
}

// Start polling setiap 15 detik
setInterval(_rtPoll, 15000);

// Juga poll segera setelah user kembali online
document.addEventListener('visibilitychange',()=>{
  if(document.visibilityState==='visible'&&gsOk&&gsUrl){
    setTimeout(_rtPoll, 500);
  }
});

// ── STARTUP ─────────────────────────────────────────────────────
// initAuth() dipanggil di sini setelah semua fungsi (render, loadDashLogo, dll) sudah terdefinisi
if(typeof initAuth==='function') initAuth();
